#[tokio::test]
async fn test_result_format_element_based() {
    // Tests ElementBased result format with element assertions
    let path = String::new();
    let mime_type = None;
    let config = None;
    let result = extract_file(&path, &mime_type, config).await.expect("should succeed");
    assert_eq!(result.mime_type.trim(), r#"application/pdf"#, "equals assertion failed");
    assert_eq!(
        result.result_format.trim(),
        r#"element_based"#,
        "equals assertion failed"
    );
    assert!(
        result.elements.len() >= 1,
        "expected at least 1 elements, got {}",
        result.elements.len()
    );
}

